mapper.select:
WITH tbm_list AS ( -- 대상 TBM 목록 질의 SELECT t.write_year, t.doc_type, t.doc_no, t.comp_id, t.work_nm, t.work_desc, t.work_place, t.same_date_yn, CASE WHEN t.same_date_yn = 'Y' THEN TRUE ELSE FALSE END AS is_same_date, CASE WHEN t.risk_yn = 'Y' THEN TRUE ELSE FALSE END AS is_risk, t.check_result, t.work_end_meeting, CASE WHEN t.tbm_date IS NOT NULL AND t.tbm_time_stt IS NOT NULL THEN TO_TIMESTAMP(t.tbm_date || ' ' || LPAD(t.tbm_time_stt, 4, '0'), 'YYYYMMDD HH24MI')::timestamp ELSE NULL END AS started_at, CASE WHEN t.tbm_date IS NOT NULL AND t.tbm_time_end IS NOT NULL THEN TO_TIMESTAMP(t.tbm_date || ' ' || LPAD(t.tbm_time_end, 4, '0'), 'YYYYMMDD HH24MI')::timestamp ELSE NULL END AS ended_at, t.created_at FROM esg.tb_toolboxmeeting t JOIN esg.tb_approval_info ai ON ai.target_type = t.doc_type AND ai.target_id = CONCAT(t.write_year, t.doc_no) AND ai.hr_id = #{hrId} -- 내가 참석자이거나, 담당자인 TBM 만 WHERE t.comp_id = #{compId} AND t.tbm_date BETWEEN #{startDate} AND #{endDate} AND t.use_yn = 'Y' GROUP BY t.write_year, t.doc_type, t.doc_no ), participants AS ( -- 담당자, 서명자 서명 정보 질의 SELECT t.write_year, t.doc_type, t.doc_no, SUM(CASE WHEN ai.type = 'leader' THEN 1 ELSE 0 END) AS leader_count, SUM(CASE WHEN ai.type = 'attend' THEN 1 ELSE 0 END) AS attendee_count, SUM(CASE WHEN ai.type = 'leader' AND ai.signature IS NOT NULL THEN 1 ELSE 0 END) AS signed_leader_count, SUM(CASE WHEN ai.type = 'attend' AND ai.signature IS NOT NULL THEN 1 ELSE 0 END) AS signed_attendee_count, MAX(CASE WHEN ai.type = 'leader' THEN ai.hr_id ELSE NULL END) AS leader_hr_id, MAX(CASE WHEN ai.type = 'leader' THEN ai.hr_nm ELSE NULL END) AS leader_name, MAX(CASE WHEN ai.type = 'leader' THEN ai.jbrp_nm ELSE NULL END) AS leader_job_title, MAX(CASE WHEN ai.type = 'leader' THEN ai.orgn_nm ELSE NULL END) AS leader_org_name, CASE WHEN MAX(CASE WHEN ai.type = 'leader' AND ai.signature IS NOT NULL THEN 1 ELSE 0 END) >= 1 THEN TRUE ELSE FALSE END AS leader_signed, SUM(CASE WHEN ai.hr_id = #{hrId} THEN 1 ELSE 0 END) AS my_count, SUM(CASE WHEN ai.hr_id = #{hrId} AND ai.signature IS NOT NULL THEN 1 ELSE 0 END) AS signed_my_count FROM esg.tb_approval_info ai JOIN tbm_list t ON ai.target_type = t.doc_type AND ai.target_id = CONCAT(t.write_year, t.doc_no) GROUP BY t.write_year, t.doc_type, t.doc_no ) SELECT -- TBM 목록 조회 질의 본문 CONCAT(t.write_year, '-', t.doc_type, '-', t.doc_no) AS id, t.work_place AS location, json_build_object( 'name', t.work_nm, 'content', t.work_desc ) AS work, t.is_same_date AS sameWorkingDate, t.is_risk AS includedRiskAssessment, CASE WHEN p.my_count > 0 THEN CASE WHEN p.my_count > p.signed_my_count THEN FALSE ELSE TRUE END ELSE NULL END AS signed, CASE WHEN p.leader_hr_id IS NOT NULL THEN json_build_object( 'hrId', p.leader_hr_id, 'hrNm', p.leader_name, 'jbrpNm', p.leader_job_title, 'orgnNm', p.leader_org_name, 'signed', p.leader_signed ) ELSE NULL END AS leader, json_build_object( 'attendee', p.attendee_count, 'signedAttendee', p.signed_attendee_count, 'leader', p.leader_count, 'signedLeader', p.signed_leader_count ) AS participantCount, t.check_result AS checkResult, t.work_end_meeting AS endMeeting, CASE WHEN t.check_result IS NULL THEN 'safetyCheck' WHEN t.work_end_meeting IS NULL THEN 'meeting' WHEN p.attendee_count != p.signed_attendee_count THEN 'waitSigns' WHEN p.leader_signed IS FALSE THEN 'leaderSigns' ELSE 'done' END AS status, t.started_at AS startedAt, t.ended_at AS endedAt, t.created_at FROM tbm_list t JOIN participants p ON t.write_year = p.write_year AND t.doc_type = p.doc_type AND t.doc_no = p.doc_no
AND t.check_result IS NOT NULL AND t.work_end_meeting IS NOT NULL AND p.attendee_count = p.signed_attendee_count AND p.leader_signed
;

mapper.update:
WITH participants AS ( SELECT src.hr_id, src.type, t1.hr_nm, t2.orgn_nm, jbrp.jbrp_nm FROM ( VALUES
(#{item.hrId}, 'attend'),
(#{leader.hrId}, 'leader') ) AS src(hr_id, param) JOIN esg.tb_hr_info t1 ON src.hr_id IS NOT null AND src.hr_id = t1.hr_id LEFT JOIN esg.tb_orgn_info t2 ON t1.orgn_id = t2.orgn_id left join esg.tb_hr_info_jbrp jbrp on jbrp.jbrp_id = t1.jbrp ), delete_1 AS ( DELETE FROM esg.tb_approval_info AS tgt WHERE tgt.target_type = 'TBM' AND tgt.target_id = split_part(#{id}, '-', 1) || split_part(#{id}, '-', 3) AND NOT EXISTS ( SELECT 1 FROM participants src WHERE src.hr_id = tgt.hr_id AND src.type = tgt.param ) ) INSERT INTO esg.tb_approval_info AS tgt ( target_type, target_id, hr_id, param, created_at, created_by, hr_nm, orgn_nm, jbrp_nm ) select 'TBM', split_part(#{id}, '-', 1) || split_part(#{id}, '-', 3), src.hr_id, src.type, now(), #{createdBy}, src.hr_nm, src.orgn_nm, src.jbrp_nm FROM participants AS src ON CONFLICT ON CONSTRAINT tb_approval_info_pk DO NOTHING ;

mapper.delete:

UPDATE esg.tb_toolboxmeeting
    SET use_yn = 'N',
        updated_at = now(),
        updated_by = #{createdBy}
WHERE CONCAT_WS('-', write_year, doc_type, doc_no) = #{id}
